    "iris-3fd1d42b": [
      {
        "speaker": "client",
        "text": "Глазная клиника Ирис.",
        "startSec": 0
      },
      {
        "speaker": "operator",
        "text": "Здравствуйте. Подскажите, пожалуйста, у меня вот такой вопрос.",
        "startSec": 3
      },
      {
        "speaker": "operator",
        "text": "Я 7 мая проходила в вашей клинике диагностику",
        "startSec": 7
      },
      {
        "speaker": "operator",
        "text": "зрения, то есть результаты все у меня есть.",
        "startSec": 11
      },
      {
        "speaker": "operator",
        "text": "Мне предложена была операция",
        "startSec": 14
      },
      {
        "speaker": "operator",
        "text": "по замене двух хрусталиков на оба глаза.",
        "startSec": 17
      },
      {
        "speaker": "operator",
        "text": "Вот сейчас я определилась, решила, что буду делать операцию.",
        "startSec": 20
      },
      {
        "speaker": "operator",
        "text": "Подскажите, пожалуйста, мои действия дальнейшие, Потому что, как мне тогда ранее объясняли, что и анализы должна сдать, и индивидуальные хрусталики должна изготовиться, я там оплатить должна. Ну вот пошагово",
        "startSec": 25
      },
      {
        "speaker": "operator",
        "text": "можно мне сориентировать?",
        "startSec": 36
      },
      {
        "speaker": "client",
        "text": "Скажите",
        "startSec": 38
      },
      {
        "speaker": "client",
        "text": "вашу фамилию, имя, отчество полностью. Фёдорова Наталья",
        "startSec": 40
      },
      {
        "speaker": "operator",
        "text": "Николаевна.",
        "startSec": 45
      },
      {
        "speaker": "operator",
        "text": "Была я у Смыковой",
        "startSec": 47
      },
      {
        "speaker": "operator",
        "text": "7 мая.",
        "startSec": 49
      },
      {
        "speaker": "client",
        "text": "Да, у вас здесь два заказных хрусталика.",
        "startSec": 58
      },
      {
        "speaker": "client",
        "text": "Смотрите, ваша",
        "startSec": 63
      },
      {
        "speaker": "client",
        "text": "диагностика",
        "startSec": 64
      },
      {
        "speaker": "client",
        "text": "актуальна месяц.",
        "startSec": 68
      },
      {
        "speaker": "client",
        "text": "Хрусталики у вас идут заказные по полной предоплате,",
        "startSec": 72
      },
      {
        "speaker": "client",
        "text": "то",
        "startSec": 76
      },
      {
        "speaker": "client",
        "text": "есть",
        "startSec": 77
      },
      {
        "speaker": "client",
        "text": "за один глаз. Это вот хрусталик, который я вижу, что вам назначила Ольга Вячеславовна.",
        "startSec": 78
      },
      {
        "speaker": "client",
        "text": "Он трифакально-торический,",
        "startSec": 83
      },
      {
        "speaker": "client",
        "text": "этот хрусталик,",
        "startSec": 86
      },
      {
        "speaker": "client",
        "text": "называется Панов Чехуголик.",
        "startSec": 87
      },
      {
        "speaker": "client",
        "text": "Стоимость",
        "startSec": 91
      },
      {
        "speaker": "client",
        "text": "операции за один глаз",
        "startSec": 92
      },
      {
        "speaker": "client",
        "text": "157",
        "startSec": 94
      }
    ],
